/*
	Name:
		Component Icon

	Description:
		Displays a Icon from the "Huge Icons" icon pack.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		name
			Type: string
			Values: Any "Huge Icon" name
			Default: ''
			Description: Select an icon by "Huge Icon" name (https://hugeicons.com/icons).

		size
			Type: string
			Values: 'xl', 'l', 'm', 's', 'xs', 'xxs'
			Default: ''
			Description: Define the icon size.

		color
			Type: string
			Values: 'primary', 'secondary', 'grey', 'lightGrey', 'white'
			Default: ''
			Description: Define the icon colour.

		style
			Type: string
			Values: 'stroke', 'duotone', 'solid', 'twotone', 'bulk'
			Default: 'stroke'
			Description: Define the icon style.

		strokeWidth
			Type: number
			Values: Any number
			Default: 2
			Description: Define the icon stroke width.

		type
			Type: string
			Values: 'rounded', 'sharp'
			Default: 'rounded'
			Description: Define the icon type.

		responsive
			Type: boolean
			Values: true, false
			Default: true
			Description: Make this icon responsive.

		...rest
			All other props are passed to <span>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	name: string,
	size?: 'xl' | 'l' | 'm' | 's' | 'xs' | 'xxs',
	color?: 'primary' | 'secondary' | 'grey' | 'lightGrey' | 'white',
	style?: 'stroke' | 'duotone' | 'solid' | 'twotone' | 'bulk',
	strokeWidth?: number,
	type?: 'rounded' | 'sharp',
	responsive?: boolean
} & React.ComponentProps<'span'>;

function Icon({
	id = '',
	className = '',
	name = '',
	size = 'm',
	color = 'grey',
	style = 'stroke',
	strokeWidth = 2,
	type = 'rounded',
	responsive = true,
	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_icon, className];

	// Size
	if (size) {
		classes.push(styles['size_' + size]);
	}

	// Colour
	if (color) {
		classes.push(styles['color_' + color]);
	}

	// Responsive
	if (responsive) {
		classes.push(styles['responsive']);
	}


	/* Dynamically import the icon from Huge Icons
	-------------------------------------------------- */
	// Format the name for the import from "calendar-01" to "Calender01Icon"

	// Replace "Icon" if it's accidentally been passed in
	name = name.replace('Icon', '');

	// Split the name on "-"
	const bits = name.split('-');

	// For each bit
	bits.forEach((bit, index) => {
		// Uppercase first letter
		bits[index] = String(bit).charAt(0).toUpperCase() + String(bit).slice(1);
	});

	// Join the bits together and add "Icon" to the end
	const formattedName = bits.join('') + 'Icon';

	// Import the icon
	const HugeIcon = require("@hugeicons/react")[formattedName];


	/* Output the component
	-------------------------------------------------- */
	return (
		<span className={classes.join(' ')} id={id} {...rest}>
			<HugeIcon
				type={type}
				color={color}
				variant={style}
				strokeWidth={strokeWidth}
			/>
		</span>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Icon;

// Types
export type { typedProps as IconTypes };
