/*
	Name:
		Component Link

	Description:
		Displays a Link.

	Params:
		id
			Type: string
			Values: Any string
			Default: ''
			Description: Add an ID to this component.

		className
			Type: string
			Values: Any string or CSS module
			Default: ''
			Description: Add a CSS class or module to this component.

		size
			Type: string
			Values: 'inherit', 'h1', 'h2', 'h3', 'h4', 'l', 'm', 's', 'xs'
			Default: 'inherit'
			Description: Define the size for the link (use 'inherit' to inherit the size from a containing <Text> component).

		href
			Type: string
			Values: Any link
			Default: ''
			Description: Define the href for the link.

		target
			Type: string
			Values: '_blank', '_self', '_parent', '_top'
			Default: '_self'
			Description: Define the target for the link.

		gap
			Type: boolean
			Values: true, false
			Default: false
			Description: Add a default gap (padding) below this component based on the text size.

		...rest
			All other props are passed to <NextLink>.
*/



/* Imports
---------------------------------------------------------------------------------------------------- */
import React from 'react';
import NextLink, { LinkProps } from 'next/link';
import H1 from '../typography/h1';
import H2 from '../typography/h2';
import H3 from '../typography/h3';
import H4 from '../typography/h4';
import Text from '../typography/text';
import styles from './style.module.css';



/* Component
---------------------------------------------------------------------------------------------------- */
type typedProps = {
	id?: string,
	className?: string,
	size?: 'inherit' | 'h1' | 'h2' | 'h3' | 'h4' | 'l' | 'm' | 's' | 'xs',
	gap?: boolean,
	href?: string,
	target?: '_blank' | '_self' | '_parent' | '_top',
	children?: React.ReactNode
} & LinkProps;

function Link({
	id = '',
	className = '',
	size = 'inherit',
	gap = false,
	href = '',
	target = '_self',
	children,

	// Support passing in event listeners from the parent
	// This ensures we don't override these as they're also used within this component
	onClick = () => {},

	...rest
}: typedProps) {
	/* Build the class list
	-------------------------------------------------- */
	const classes = [styles.component_link, className];


	/* Define the link
	-------------------------------------------------- */
	let output = (
		<NextLink
			id={id}
			href={href}
			target={target}
			className={styles.link}
			onClick={handleClick}
			{...rest}
		>
			{children}
		</NextLink>
	);


	/* Define the text size (as a wrapping element)
	-------------------------------------------------- */
	if (size !== 'inherit') {
		if (size === 'h1') {
			output = <H1 gap={gap} className={styles.text}>{output}</H1>;
		}
		else if (size === 'h2') {
			output = <H2 gap={gap} className={styles.text}>{output}</H2>;
		}
		else if (size === 'h3') {
			output = <H3 gap={gap} className={styles.text}>{output}</H3>;
		}
		else if (size === 'h4') {
			output = <H4 gap={gap} className={styles.text}>{output}</H4>;
		}
		else {
			output = <Text size={size} gap={gap} className={styles.text}>{output}</Text>;
		}
	}


	/* On click of the <NextLink> element
	-------------------------------------------------- */
	function handleClick(event: React.MouseEvent<HTMLAnchorElement>) {
		// If there's no href, prevent this from doing anything
		if (href === '') {
			event.preventDefault();
		}

		// Also call the event handler that could be passed in from the parent
		onClick(event);
	}


	/* Output the component
	-------------------------------------------------- */
	return (
		<div className={classes.join(' ')}>
			{output}
		</div>
	);
}



/* Exports
---------------------------------------------------------------------------------------------------- */
// Component
export default Link;

// Types
export type { typedProps as LinkTypes };
